#include <bits/stdc++.h>
using namespace std;
const int maxn=1e6+5;
int n,m,a[maxn];
bool check(int x) {
	int sum=0;
	for(int i=1; i<=n; i++) {
		if(a[i]>x) {
			sum+=a[i]-x;
		}
		if(sum>=m) {
			return 1;
		}
	}
	return 0;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	int h=0;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
		h=max(h,a[i]);
	}
	int l=0,r=h;
	while(l<r) {
		int mid=l+r+1>>1;
		if(check(mid)) {
			l=mid;
		} else {
			r=mid-1;
		}
	}
	cout<<l;
	return 0;
}
